    "body": "{\n  \"name\": \"Remodex Web Deck\",\n  \"short_name\": \"Web Deck\",\n  \"start_url\": \"/app/\",\n  \"scope\": \"/app/\",\n  \"display\": \"standalone\",\n  \"background_color\": \"#09111d\",\n  \"theme_color\": \"#111827\",\n  \"description\": \"Browser client skeleton for the Remodex relay.\",\n  \"icons\": [\n    {\n      \"src\": \"/app/icon.svg\",\n      \"sizes\": \"any\",\n      \"type\": \"image/svg+xml\",\n      \"purpose\": \"any maskable\"\n    }\n  ]\n}\n",
